&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;
&lt;ui version=&quot;4.0&quot;&gt;
 &lt;class&gt;OptionDialog&lt;/class&gt;
 &lt;widget class=&quot;QDialog&quot; name=&quot;OptionDialog&quot;&gt;
  &lt;property name=&quot;geometry&quot;&gt;
   &lt;rect&gt;
    &lt;x&gt;0&lt;/x&gt;
    &lt;y&gt;0&lt;/y&gt;
    &lt;width&gt;414&lt;/width&gt;
    &lt;height&gt;313&lt;/height&gt;
   &lt;/rect&gt;
  &lt;/property&gt;
  &lt;property name=&quot;windowTitle&quot;&gt;
   &lt;string&gt;Add Options&lt;/string&gt;
  &lt;/property&gt;
  &lt;layout class=&quot;QHBoxLayout&quot; name=&quot;horizontalLayout_3&quot;&gt;
   &lt;item&gt;
    &lt;layout class=&quot;QHBoxLayout&quot; name=&quot;horizontalLayout_2&quot;&gt;
     &lt;item&gt;
      &lt;layout class=&quot;QVBoxLayout&quot; name=&quot;verticalLayout_2&quot;&gt;
       &lt;item&gt;
        &lt;layout class=&quot;QHBoxLayout&quot; name=&quot;horizontalLayout&quot;&gt;
         &lt;item&gt;
          &lt;widget class=&quot;QLabel&quot; name=&quot;label&quot;&gt;
           &lt;property name=&quot;text&quot;&gt;
            &lt;string&gt;Option&lt;/string&gt;
           &lt;/property&gt;
          &lt;/widget&gt;
         &lt;/item&gt;
         &lt;item&gt;
          &lt;widget class=&quot;QComboBox&quot; name=&quot;optionComboBox&quot;&gt;
           &lt;property name=&quot;sizePolicy&quot;&gt;
            &lt;sizepolicy hsizetype=&quot;Fixed&quot; vsizetype=&quot;Fixed&quot;&gt;
             &lt;horstretch&gt;0&lt;/horstretch&gt;
             &lt;verstretch&gt;0&lt;/verstretch&gt;
            &lt;/sizepolicy&gt;
           &lt;/property&gt;
           &lt;property name=&quot;minimumSize&quot;&gt;
            &lt;size&gt;
             &lt;width&gt;120&lt;/width&gt;
             &lt;height&gt;0&lt;/height&gt;
            &lt;/size&gt;
           &lt;/property&gt;
          &lt;/widget&gt;
         &lt;/item&gt;
         &lt;item&gt;
          &lt;widget class=&quot;QLineEdit&quot; name=&quot;optionValueEdit&quot;/&gt;
         &lt;/item&gt;
        &lt;/layout&gt;
       &lt;/item&gt;
       &lt;item&gt;
        &lt;widget class=&quot;QTableWidget&quot; name=&quot;tableWidget&quot;&gt;
         &lt;property name=&quot;selectionMode&quot;&gt;
          &lt;enum&gt;QAbstractItemView::SingleSelection&lt;/enum&gt;
         &lt;/property&gt;
         &lt;property name=&quot;selectionBehavior&quot;&gt;
          &lt;enum&gt;QAbstractItemView::SelectRows&lt;/enum&gt;
         &lt;/property&gt;
         &lt;property name=&quot;columnCount&quot;&gt;
          &lt;number&gt;2&lt;/number&gt;
         &lt;/property&gt;
         &lt;column/&gt;
         &lt;column/&gt;
        &lt;/widget&gt;
       &lt;/item&gt;
       &lt;item&gt;
        &lt;widget class=&quot;QDialogButtonBox&quot; name=&quot;buttonBox&quot;&gt;
         &lt;property name=&quot;orientation&quot;&gt;
          &lt;enum&gt;Qt::Horizontal&lt;/enum&gt;
         &lt;/property&gt;
         &lt;property name=&quot;standardButtons&quot;&gt;
          &lt;set&gt;QDialogButtonBox::Cancel|QDialogButtonBox::Ok&lt;/set&gt;
         &lt;/property&gt;
        &lt;/widget&gt;
       &lt;/item&gt;
      &lt;/layout&gt;
     &lt;/item&gt;
     &lt;item&gt;
      &lt;layout class=&quot;QVBoxLayout&quot; name=&quot;verticalLayout&quot;&gt;
       &lt;item&gt;
        &lt;widget class=&quot;QPushButton&quot; name=&quot;addButton&quot;&gt;
         &lt;property name=&quot;sizePolicy&quot;&gt;
          &lt;sizepolicy hsizetype=&quot;Fixed&quot; vsizetype=&quot;Fixed&quot;&gt;
           &lt;horstretch&gt;0&lt;/horstretch&gt;
           &lt;verstretch&gt;0&lt;/verstretch&gt;
          &lt;/sizepolicy&gt;
         &lt;/property&gt;
         &lt;property name=&quot;minimumSize&quot;&gt;
          &lt;size&gt;
           &lt;width&gt;100&lt;/width&gt;
           &lt;height&gt;0&lt;/height&gt;
          &lt;/size&gt;
         &lt;/property&gt;
         &lt;property name=&quot;text&quot;&gt;
          &lt;string&gt;Add&lt;/string&gt;
         &lt;/property&gt;
        &lt;/widget&gt;
       &lt;/item&gt;
       &lt;item&gt;
        &lt;widget class=&quot;QPushButton&quot; name=&quot;removeButton&quot;&gt;
         &lt;property name=&quot;enabled&quot;&gt;
          &lt;bool&gt;false&lt;/bool&gt;
         &lt;/property&gt;
         &lt;property name=&quot;text&quot;&gt;
          &lt;string&gt;Remove&lt;/string&gt;
         &lt;/property&gt;
        &lt;/widget&gt;
       &lt;/item&gt;
       &lt;item&gt;
        &lt;widget class=&quot;QPushButton&quot; name=&quot;clearButton&quot;&gt;
         &lt;property name=&quot;text&quot;&gt;
          &lt;string&gt;Clear&lt;/string&gt;
         &lt;/property&gt;
        &lt;/widget&gt;
       &lt;/item&gt;
       &lt;item&gt;
        &lt;spacer name=&quot;verticalSpacer&quot;&gt;
         &lt;property name=&quot;orientation&quot;&gt;
          &lt;enum&gt;Qt::Vertical&lt;/enum&gt;
         &lt;/property&gt;
         &lt;property name=&quot;sizeHint&quot; stdset=&quot;0&quot;&gt;
          &lt;size&gt;
           &lt;width&gt;20&lt;/width&gt;
           &lt;height&gt;40&lt;/height&gt;
          &lt;/size&gt;
         &lt;/property&gt;
        &lt;/spacer&gt;
       &lt;/item&gt;
      &lt;/layout&gt;
     &lt;/item&gt;
    &lt;/layout&gt;
   &lt;/item&gt;
  &lt;/layout&gt;
 &lt;/widget&gt;
 &lt;resources/&gt;
 &lt;connections&gt;
  &lt;connection&gt;
   &lt;sender&gt;buttonBox&lt;/sender&gt;
   &lt;signal&gt;accepted()&lt;/signal&gt;
   &lt;receiver&gt;OptionDialog&lt;/receiver&gt;
   &lt;slot&gt;accept()&lt;/slot&gt;
   &lt;hints&gt;
    &lt;hint type=&quot;sourcelabel&quot;&gt;
     &lt;x&gt;152&lt;/x&gt;
     &lt;y&gt;289&lt;/y&gt;
    &lt;/hint&gt;
    &lt;hint type=&quot;destinationlabel&quot;&gt;
     &lt;x&gt;206&lt;/x&gt;
     &lt;y&gt;156&lt;/y&gt;
    &lt;/hint&gt;
   &lt;/hints&gt;
  &lt;/connection&gt;
  &lt;connection&gt;
   &lt;sender&gt;buttonBox&lt;/sender&gt;
   &lt;signal&gt;rejected()&lt;/signal&gt;
   &lt;receiver&gt;OptionDialog&lt;/receiver&gt;
   &lt;slot&gt;reject()&lt;/slot&gt;
   &lt;hints&gt;
    &lt;hint type=&quot;sourcelabel&quot;&gt;
     &lt;x&gt;152&lt;/x&gt;
     &lt;y&gt;289&lt;/y&gt;
    &lt;/hint&gt;
    &lt;hint type=&quot;destinationlabel&quot;&gt;
     &lt;x&gt;206&lt;/x&gt;
     &lt;y&gt;156&lt;/y&gt;
    &lt;/hint&gt;
   &lt;/hints&gt;
  &lt;/connection&gt;
 &lt;/connections&gt;
&lt;/ui&gt;
